Make the following polish fixes:

1. **`src/ui/popup.rs`** — Change the help text for `/copy` from `"Copy pairing command to clipboard (OSC 52)"` to just `"Copy pairing command to clipboard"`. Remove the OSC 52 jargon.

2. **`src/terminal/clipboard.rs`** — Add unit tests for the `base64_encode` function at the bottom of the file:

```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_base64_encode_empty() {
        assert_eq!(base64_encode(b""), "");
    }

    #[test]
    fn test_base64_encode_rfc4648_vectors() {
        assert_eq!(base64_encode(b"f"), "Zg==");
        assert_eq!(base64_encode(b"fo"), "Zm8=");
        assert_eq!(base64_encode(b"foo"), "Zm9v");
        assert_eq!(base64_encode(b"foob"), "Zm9vYg==");
        assert_eq!(base64_encode(b"fooba"), "Zm9vYmE=");
        assert_eq!(base64_encode(b"foobar"), "Zm9vYmFy");
    }

    #[test]
    fn test_base64_encode_pairing_command() {
        let cmd = "cargo run -- --shell-connect 1234 --port 56789";
        let encoded = base64_encode(cmd.as_bytes());
        // Verify it's valid base64 by checking length and character set
        assert_eq!(encoded.len() % 4, 0);
        assert!(encoded.chars().all(|c| c.is_ascii_alphanumeric() || c == '+' || c == '/' || c == '='));
    }
}
```

3. Run `cargo test` to confirm all tests pass.

